import React, { useState, useEffect } from 'react';
import { motion, useScroll, useSpring } from 'framer-motion';
import { Check, Shield, Award, Lock, Star, ChevronDown, Menu, X } from 'lucide-react';
import { cn } from '@/lib/utils';

// --- Types & Data ---

interface Testimonial {
  id: number;
  quote: string;
  author: string;
  role: string;
  location: string;
}
interface CurriculumItem {
  module: string;
  instructor: string;
  time: string;
}
interface CurriculumDay {
  title: string;
  items: CurriculumItem[];
}
interface NavLink {
  label: string;
  href: string;
}
interface TrustStat {
  value: string;
  label: string;
}
interface Inclusion {
  text: string;
}
const NAV_LINKS: NavLink[] = [{
  label: 'Curriculum',
  href: '#curriculum'
}, {
  label: 'Instructor',
  href: '#instructor'
}, {
  label: 'Reviews',
  href: '#reviews'
}, {
  label: 'Enroll',
  href: '#enroll'
}];
const HEADER_STATS: TrustStat[] = [{
  value: '2,400+',
  label: 'Students'
}, {
  value: '4.9★',
  label: 'Rating'
}, {
  value: '97%',
  label: 'Complete'
}];
const TESTIMONIALS: Testimonial[] = [{
  id: 1,
  quote: "This masterclass completely transformed how I think about bread. Chef Elena's sourdough module alone was worth every penny.",
  author: 'M.T.',
  role: 'Home Baker',
  location: 'London'
}, {
  id: 2,
  quote: 'I went from nervous beginner to running my own pop-up bakery in six months. The curriculum is genuinely world-class.',
  author: 'R.K.',
  role: 'Culinary Graduate',
  location: 'New York'
}, {
  id: 3,
  quote: 'The fermentation session changed everything. I finally understand the science behind the craft.',
  author: 'S.B.',
  role: 'Pastry Chef',
  location: 'Paris'
}];
const CURRICULUM: CurriculumDay[] = [{
  title: 'DAY 01 — FOUNDATIONS OF BREAD',
  items: [{
    module: 'Sourdough Starter Science',
    instructor: 'Chef Elena Russo',
    time: '9:00-10:30 AM'
  }, {
    module: 'Flour Selection and Hydration',
    instructor: 'Chef Marcus Webb',
    time: '11:00-12:30 PM'
  }, {
    module: 'Fermentation Fundamentals',
    instructor: 'Chef Elena Russo',
    time: '2:00-3:30 PM'
  }, {
    module: 'Shaping and Scoring',
    instructor: 'Chef James Allard',
    time: '4:00-5:00 PM'
  }]
}, {
  title: 'DAY 02 — ADVANCED TECHNIQUES',
  items: [{
    module: 'Enriched Doughs and Brioche',
    instructor: 'Chef Marcus Webb',
    time: '9:00-10:30 AM'
  }, {
    module: 'Laminated Pastry Foundations',
    instructor: 'Chef James Allard',
    time: '11:00-12:30 PM'
  }, {
    module: 'Oven Dynamics and Steam',
    instructor: 'Chef Elena Russo',
    time: '2:00-3:30 PM'
  }, {
    module: 'Crust Colour and Texture',
    instructor: 'Chef Marcus Webb',
    time: '4:00-5:00 PM'
  }]
}, {
  title: 'DAY 03 — MASTERY AND REFINEMENT',
  items: [{
    module: 'Regional Bread Traditions',
    instructor: 'Chef James Allard',
    time: '9:00-10:30 AM'
  }, {
    module: 'Menu Development',
    instructor: 'Chef Elena Russo',
    time: '11:00-12:30 PM'
  }, {
    module: 'Live Critique and Feedback',
    instructor: 'All Instructors',
    time: '2:00-4:00 PM'
  }, {
    module: 'Final Showcase and Certification',
    instructor: 'All Instructors',
    time: '4:00-5:30 PM'
  }]
}];
const INCLUSIONS: Inclusion[] = [{
  text: '3-Day Intensive Curriculum (12 modules)'
}, {
  text: 'Access to 3 World-Class Instructors'
}, {
  text: 'Lifetime access to recorded sessions'
}, {
  text: 'Downloadable recipe and technique PDFs'
}, {
  text: 'Private student community access'
}, {
  text: 'Live Q&A session recordings'
}, {
  text: 'Official Certification of Mastery'
}, {
  text: '30-Day money-back guarantee'
}];
const PUBLICATIONS = ['THE NEW YORK TIMES', 'BON APPETIT', 'FOOD AND WINE', 'THE GUARDIAN', 'SAVEUR', 'EATER'];
const TRUST_STATS = [{
  value: '2,400+',
  label: 'STUDENTS ENROLLED',
  desc: 'Across 40+ countries'
}, {
  value: '97%',
  label: 'COMPLETION RATE',
  desc: 'Industry-leading retention'
}, {
  value: '18+',
  label: 'YEARS EXPERTISE',
  desc: 'Combined instructor experience'
}, {
  value: '4.9',
  label: 'AVERAGE RATING',
  desc: 'From 1,200+ reviews'
}];

// --- Shared UI Atoms ---

const SectionEyebrow = ({
  children,
  className,
  light = false
}: {
  children: React.ReactNode;
  className?: string;
  light?: boolean;
}) => <span className={cn('block uppercase tracking-[0.4em] text-[11px] font-bold mb-6', light ? 'text-white/60' : 'text-[#1B2A8B]', className)}>
    {children}
  </span>;
const SectionHeadline = ({
  children,
  className,
  light = false
}: {
  children: React.ReactNode;
  className?: string;
  light?: boolean;
}) => <h2 className={cn('font-black uppercase leading-[0.9] tracking-tight mb-8', light ? 'text-white' : 'text-[#1B2A8B]', className)}>
    {children}
  </h2>;

// --- Top Navigation Bar ---

const TopNav = () => {
  const [mobileOpen, setMobileOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  useEffect(() => {
    const handler = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', handler);
    return () => window.removeEventListener('scroll', handler);
  }, []);
  return <header className={cn('fixed top-0 left-0 right-0 z-50 transition-all duration-300', scrolled ? 'bg-white/97 backdrop-blur-sm border-b border-[#E8E8E8] shadow-sm' : 'bg-white border-b border-[#E8E8E8]')}>
      {/* Trust stats strip — visible on desktop */}
      <div className="hidden md:flex items-center justify-center bg-[#1B2A8B] py-2 px-6 gap-10">
        {HEADER_STATS.map(stat => <div key={stat.label} className="flex items-center gap-2">
            <span className="text-white font-black text-[13px] tracking-tight">{stat.value}</span>
            <span className="text-white/50 text-[11px] uppercase tracking-widest">{stat.label}</span>
          </div>)}
        <span className="text-white/30 text-[10px] mx-2">|</span>
        <span className="text-white/70 text-[11px] uppercase tracking-widest">
          <span className="text-yellow-300 font-black">⚠ </span>
          <span>Only 14 seats remaining in the July cohort</span>
        </span>
      </div>

      {/* Main nav row */}
      <nav className="flex items-center justify-between px-6 md:px-10 h-[64px]">
        {/* Logo */}
        <a href="#" className="flex flex-col leading-none">
          <span className="text-[#1B2A8B] font-black uppercase text-[18px] tracking-tighter leading-none">
            ARTISAN BAKE
          </span>
          <div className="h-[2px] w-[44px] bg-[#1B2A8B] mt-[3px]" />
        </a>

        {/* Desktop nav links */}
        <div className="hidden md:flex items-center gap-8">
          {NAV_LINKS.map(link => <a key={link.href} href={link.href} className="text-[#4A4A4A] hover:text-[#1B2A8B] font-black uppercase text-[11px] tracking-[0.2em] transition-colors">
              {link.label}
            </a>)}
        </div>

        {/* Desktop CTA + mobile stats */}
        <div className="flex items-center gap-6">
          {/* Mobile trust strip */}
          <div className="flex md:hidden items-center gap-4">
            {HEADER_STATS.slice(0, 2).map(stat => <div key={stat.label} className="flex flex-col leading-none">
                <span className="text-[#1B2A8B] font-black text-[12px]">{stat.value}</span>
                <span className="text-[#AAAAAA] text-[9px] uppercase tracking-wider">{stat.label}</span>
              </div>)}
          </div>

          <a href="#enroll" className="hidden md:inline-flex items-center justify-center bg-[#1B2A8B] text-white px-6 py-3 font-black uppercase tracking-widest text-[11px] transition-all hover:bg-[#1B2A8B]/90 active:scale-95">
            ENROLL — $497
          </a>

          {/* Mobile menu toggle */}
          <button className="md:hidden text-[#1B2A8B] p-1" onClick={() => setMobileOpen(v => !v)} aria-label="Toggle menu">
            {mobileOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>
      </nav>

      {/* Mobile dropdown menu */}
      {mobileOpen && <div className="md:hidden bg-white border-t border-[#E8E8E8] px-6 py-6 flex flex-col gap-6">
          {NAV_LINKS.map(link => <a key={link.href} href={link.href} onClick={() => setMobileOpen(false)} className="text-[#4A4A4A] hover:text-[#1B2A8B] font-black uppercase text-[13px] tracking-widest transition-colors">
              {link.label}
            </a>)}
          <a href="#enroll" onClick={() => setMobileOpen(false)} className="inline-flex items-center justify-center bg-[#1B2A8B] text-white py-4 font-black uppercase tracking-widest text-[13px] transition-all hover:bg-[#1B2A8B]/90">
            ENROLL NOW — $497
          </a>
        </div>}
    </header>;
};

// --- Hero ---

const Hero = () => <section id="hero" className="relative flex flex-col md:flex-row min-h-screen overflow-hidden border-b border-[#E8E8E8] pt-[64px] md:pt-[96px]">
    {/* Left Column */}
    <div className="w-full md:w-[55%] bg-white flex flex-col justify-center px-6 md:px-[100px] py-20">
      <SectionEyebrow>THE ART OF BREAD</SectionEyebrow>
      <h1 className="text-[#1B2A8B] font-black uppercase text-[58px] md:text-[88px] leading-[0.85] tracking-tight mb-8 max-w-[700px]">
        Master the Craft of{' '}
        <br />
        Artisan Baking
      </h1>
      <p className="text-[#4A4A4A] text-[17px] leading-relaxed max-w-[480px] mb-12">
        Experience a world-class culinary journey from foundational science to the final perfect crust.
      </p>

      {/* Inline trust indicators */}
      <div className="flex flex-wrap gap-6 mb-12">
        <div className="flex items-center gap-2">
          <div className="flex gap-[2px]">
            {[0, 1, 2, 3, 4].map(i => <Star key={i} size={13} fill="#F5A623" color="#F5A623" />)}
          </div>
          <span className="text-[#4A4A4A] text-[13px] font-bold">4.9 from 1,200+ reviews</span>
        </div>
        <div className="w-px h-4 bg-[#E0E0E0] self-center" />
        <span className="text-[#4A4A4A] text-[13px]">
          <span className="font-black text-[#1B2A8B]">2,400+</span> students enrolled
        </span>
      </div>

      <div>
        <a href="#enroll" className="inline-flex items-center justify-center bg-[#1B2A8B] text-white px-10 py-5 font-black uppercase tracking-widest text-[14px] transition-all hover:bg-[#1B2A8B]/90 active:scale-95">
          ENROLL NOW
        </a>
      </div>
    </div>

    {/* Right Column */}
    <div className="w-full md:w-[45%] h-[400px] md:h-auto overflow-hidden">
      <img src="https://images.unsplash.com/photo-1509440159596-0249088772ff?auto=format&fit=crop&q=80&w=1200" alt="Artisan Bread Close-up" className="w-full h-full object-cover grayscale brightness-90" />
    </div>
  </section>;

// --- Marquee Ticker ---

const MarqueeTicker = () => {
  const phrases = ['ARTISAN BREAD TECHNIQUES', 'WORLD-CLASS INSTRUCTORS', 'LIMITED COHORT SEATS', 'HANDS-ON TRAINING', 'CERTIFICATION INCLUDED', 'SOURDOUGH MASTERY', 'ENROLL NOW'];
  return <div className="w-full h-[80px] bg-[#1B2A8B] flex items-center overflow-hidden border-y border-white/10">
      <motion.div className="flex whitespace-nowrap gap-12" animate={{
      x: [0, -1000]
    }} transition={{
      duration: 30,
      repeat: Infinity,
      ease: 'linear'
    }}>
        {[0, 1, 2, 3].map(i => <div key={i} className="flex items-center gap-12">
            {phrases.map((phrase, idx) => <div key={idx} className="flex items-center gap-12">
                <span className="text-white font-black uppercase text-[16px] tracking-widest">{phrase}</span>
                <span className="text-white text-[10px]">◆</span>
              </div>)}
          </div>)}
      </motion.div>
    </div>;
};

// --- Featured In ---

const FeaturedIn = () => <section className="w-full py-14 bg-white flex flex-col items-center justify-center border-b border-[#E8E8E8]">
    <SectionEyebrow className="mb-8 text-center !tracking-[0.6em] !text-[#AAAAAA]">
      AS FEATURED IN
    </SectionEyebrow>
    <div className="flex flex-wrap justify-center items-center gap-x-10 gap-y-6 px-6">
      {PUBLICATIONS.map(pub => <span key={pub} className="text-[#CCCCCC] hover:text-[#333] transition-colors font-black uppercase text-[16px] md:text-[20px] tracking-tight cursor-default">
          {pub}
        </span>)}
    </div>
  </section>;

// --- Awareness Statement ---

const AwarenessStatement = () => <section className="w-full min-h-[85vh] bg-[#1B2A8B] flex flex-col items-center justify-center text-center px-6 py-24">
    <motion.div initial={{
    opacity: 0,
    y: 30
  }} whileInView={{
    opacity: 1,
    y: 0
  }} transition={{
    duration: 1,
    ease: 'easeOut'
  }} viewport={{
    once: true
  }}>
      <h2 className="text-white font-black uppercase text-[54px] md:text-[100px] leading-[0.9] tracking-tight max-w-[1000px] mb-12">
        MOST PEOPLE
        <br />
        BAKE BREAD.
        <br />
        FEW TRULY
        <br />
        UNDERSTAND IT.
      </h2>
      <p className="text-white/80 text-[18px] md:text-[20px] leading-relaxed max-w-[560px] mx-auto">
        Our masterclass teaches you the science, craft, and intuition behind every perfect loaf.
      </p>
    </motion.div>
  </section>;

// --- Curriculum ---

const Curriculum = () => <section id="curriculum" className="w-full bg-white py-24 px-6 md:px-[100px]">
    <div className="max-w-[1240px] mx-auto">
      <div className="mb-16">
        <SectionEyebrow>THE CURRICULUM</SectionEyebrow>
        <SectionHeadline className="text-[56px] md:text-[80px] mb-4">
          WHAT YOU WILL LEARN
        </SectionHeadline>
        <p className="text-[#4A4A4A] text-[18px]">An intensive roadmap to professional-grade baking.</p>
      </div>

      <div className="w-full overflow-x-auto">
        <table className="w-full border-collapse">
          <thead>
            <tr className="border-b-2 border-[#1B2A8B] text-left">
              <th className="pb-4 pt-2 uppercase text-[11px] font-black text-[#4A4A4A] tracking-widest w-[80px]">
                #
              </th>
              <th className="pb-4 pt-2 uppercase text-[11px] font-black text-[#4A4A4A] tracking-widest">
                Module
              </th>
              <th className="pb-4 pt-2 uppercase text-[11px] font-black text-[#4A4A4A] tracking-widest">
                Instructor
              </th>
              <th className="pb-4 pt-2 uppercase text-[11px] font-black text-[#4A4A4A] tracking-widest text-right">
                Time
              </th>
            </tr>
          </thead>
          <tbody>
            {CURRICULUM.map((day, dayIdx) => <React.Fragment key={day.title}>
                <tr className="bg-[#F0F2FA]">
                  <td colSpan={4} className="py-4 px-4">
                    <span className="text-[#1B2A8B] font-black uppercase text-[16px] tracking-tight">
                      {day.title}
                    </span>
                  </td>
                </tr>
                {day.items.map((item, itemIdx) => <tr key={`${dayIdx}-${itemIdx}`} className="border-b border-[#E0E0E0] group hover:bg-[#F9F9F9] transition-colors">
                    <td className="py-5 px-4 text-[#AAAAAA] font-medium text-[14px]">
                      {String(itemIdx + 1).padStart(2, '0')}
                    </td>
                    <td className="py-5 px-4">
                      <span className="text-[#1B2A8B] font-bold text-[16px] block mb-1">
                        {item.module}
                      </span>
                      <span className="text-[#4A4A4A] text-[13px] md:hidden block">{item.instructor}</span>
                    </td>
                    <td className="py-5 px-4 hidden md:table-cell">
                      <span className="text-[#4A4A4A] text-[15px]">{item.instructor}</span>
                    </td>
                    <td className="py-5 px-4 text-right">
                      <span className="text-[#4A4A4A] text-[14px] font-mono whitespace-nowrap">
                        {item.time}
                      </span>
                    </td>
                  </tr>)}
              </React.Fragment>)}
          </tbody>
        </table>
      </div>
    </div>
  </section>;

// --- Testimonials ---

const Testimonials = () => <section id="reviews" className="w-full bg-[#F7F7F9] py-28 px-6">
    <div className="max-w-[1240px] mx-auto text-center mb-16">
      <SectionEyebrow>TESTIMONIALS</SectionEyebrow>
      <SectionHeadline className="text-[48px] md:text-[60px]">WHAT OUR STUDENTS SAY</SectionHeadline>
    </div>

    <div className="max-w-[1240px] mx-auto grid grid-cols-1 md:grid-cols-3 gap-6">
      {TESTIMONIALS.map(t => <div key={t.id} className="bg-white border border-[#E8E8E8] p-10 flex flex-col justify-between hover:shadow-xl transition-all duration-500">
          <div>
            <div className="flex gap-1 mb-7">
              {[0, 1, 2, 3, 4].map(i => <Star key={i} size={16} fill="#F5A623" color="#F5A623" />)}
            </div>
            <p className="text-[#4A4A4A] text-[17px] leading-relaxed italic mb-10">"{t.quote}"</p>
          </div>

          <div className="pt-7 border-t border-[#E8E8E8] flex items-center gap-4">
            <div className="w-11 h-11 rounded-full bg-[#1B2A8B] flex items-center justify-center text-white font-black text-[13px] shrink-0">
              {t.author}
            </div>
            <div className="flex flex-col">
              <span className="text-[#1B2A8B] font-black text-[13px] uppercase tracking-wider">
                {t.role}
              </span>
              <span className="text-[#AAAAAA] text-[11px] uppercase tracking-widest">{t.location}</span>
            </div>
          </div>
        </div>)}
    </div>
  </section>;

// --- Instructor Bio ---

const InstructorBio = () => <section id="instructor" className="relative flex flex-col md:flex-row min-h-[85vh] overflow-hidden">
    <div className="w-full md:w-[45%] h-[480px] md:h-auto overflow-hidden">
      <img src="https://images.unsplash.com/photo-1583394838336-acd977736f90?auto=format&fit=crop&q=80&w=1200" alt="Chef Elena Russo" className="w-full h-full object-cover grayscale" />
    </div>

    <div className="w-full md:w-[55%] bg-white flex flex-col justify-center px-6 md:px-20 py-24">
      <SectionEyebrow>LEAD INSTRUCTOR</SectionEyebrow>
      <SectionHeadline className="text-[48px] md:text-[72px]">
        CHEF ELENA RUSSO
      </SectionHeadline>

      <div className="space-y-8 mb-14 max-w-[580px]">
        <p className="text-[#4A4A4A] text-[16px] leading-relaxed pl-6 border-l-4 border-[#1B2A8B]">
          Trained at the prestigious Ferrandi Paris and having led artisanal programs across Europe, Elena Russo brings nearly two decades of deep-rooted expertise to the kitchen.
        </p>
        <p className="text-[#4A4A4A] text-[16px] leading-relaxed pl-6 border-l-4 border-[#1B2A8B]">
          Her philosophy centers on the marriage of ancient techniques and modern science—understanding the microscopic dance of yeast as clearly as the rhythmic motion of kneading.
        </p>
        <p className="text-[#4A4A4A] text-[16px] leading-relaxed pl-6 border-l-4 border-[#1B2A8B]">
          Elena's teaching style is rigorous yet intuitive, designed to move students past following recipes into a state of true culinary fluency.
        </p>
      </div>

      <div className="flex flex-wrap gap-4">
        <div className="flex-1 min-w-[130px] border-2 border-[#1B2A8B] p-5 text-center">
          <span className="block text-[#1B2A8B] font-black text-[28px] leading-none mb-1">18+</span>
          <span className="block text-[#1B2A8B] font-bold text-[10px] uppercase tracking-widest">
            Years Experience
          </span>
        </div>
        <div className="flex-1 min-w-[130px] border-2 border-[#1B2A8B] p-5 text-center">
          <span className="block text-[#1B2A8B] font-black text-[28px] leading-none mb-1">12-YR</span>
          <span className="block text-[#1B2A8B] font-bold text-[10px] uppercase tracking-widest">
            Starter Age
          </span>
        </div>
        <div className="flex-1 min-w-[130px] border-2 border-[#1B2A8B] p-5 text-center">
          <span className="block text-[#1B2A8B] font-black text-[28px] leading-none mb-1">MASTER</span>
          <span className="block text-[#1B2A8B] font-bold text-[10px] uppercase tracking-widest">
            Boulanger Level
          </span>
        </div>
      </div>
    </div>
  </section>;

// --- Trust Stats Band ---

const TrustBand = () => <section className="w-full bg-white py-24 px-6 border-y border-[#E8E8E8]">
    <div className="max-w-[1240px] mx-auto">
      <div className="grid grid-cols-2 md:grid-cols-4 gap-y-12">
        {TRUST_STATS.map((stat, idx) => <div key={stat.label} className={cn('px-6 text-center', idx !== TRUST_STATS.length - 1 ? 'md:border-r border-[#E0E0E0]' : '')}>
            <span className="block text-[#1B2A8B] font-black text-[44px] md:text-[56px] leading-tight mb-1 tracking-tight">
              {stat.value}
            </span>
            <span className="block text-[#4A4A4A] font-black text-[11px] uppercase tracking-widest mb-1">
              {stat.label}
            </span>
            <span className="block text-[#AAAAAA] text-[12px]">{stat.desc}</span>
          </div>)}
      </div>

      <div className="mt-20 flex flex-col md:flex-row items-center justify-center gap-10 border-t border-[#E0E0E0] pt-14">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-[#F0F2FA] flex items-center justify-center border border-[#E0E0E0]">
            <Shield className="text-[#1B2A8B]" size={18} />
          </div>
          <span className="text-[#4A4A4A] font-bold text-[12px] uppercase tracking-wider">
            30-Day Money-Back Guarantee
          </span>
        </div>
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-[#F0F2FA] flex items-center justify-center border border-[#E0E0E0]">
            <Award className="text-[#1B2A8B]" size={18} />
          </div>
          <span className="text-[#4A4A4A] font-bold text-[12px] uppercase tracking-wider">
            Certified Curriculum
          </span>
        </div>
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-[#F0F2FA] flex items-center justify-center border border-[#E0E0E0]">
            <Lock className="text-[#1B2A8B]" size={18} />
          </div>
